Điều gì sai với component này?

function Greeting({ name }: { name: string }) {
  useEffect(() => {
    document.title = name;
  }); // missing dependency

  return <h1>Hello, {name}!</h1>;
}

Điều gì sai với code này?

const Button = (props) => {
  return <button style={{ color: props.color }}>{props.label}</button>;
};
Button.defaultProps = { color: "#333", label: "Click me" };
